--模块初始化入口
--注册事件监听
--注册协议监听
--预处理数据
function ModelVip:OnModelInit()
    self:ParseConfig()
end

--在协议数据处理完之后需要调用finish
function ModelVip:OnModelRequest()
    self:ModelFinish()
