function ModelVip:GetIsHookInVipEff() --挂机vip加成
    local viplv = gModelPlayer:GetVipLevel()
    local vipConfig = self._vipConfigT[viplv]
    if not vipConfig then
        return false
    end
    local onHook=  vipConfig.onHook
    if onHook>0 then
        return true,onHook
    end
    return false
end

function ModelVip:GetGoldBuyBonusInVipEff() --金币购买vip加成
    local viplv = gModelPlayer:GetVipLevel()
    local vipConfig = self._vipConfigT[viplv]
    if not vipConfig then
        return false
    end
    local goldBuyBonus =  vipConfig.goldBuyBonus
    if goldBuyBonus > 0 then
        return goldBuyBonus
    end
    return false
end

function ModelVip:GetOnHookTime()
    local curVip = gModelPlayer:GetVipLevel()
    local cfg = self._vipConfigT[curVip]
    local extraTime = cfg.onHookTime
    local min = math.floor(extraTime/60)
    return min
end

function ModelVip:GetOnHookOutLineTime()
    local curVip = gModelPlayer:GetVipLevel()
    local cfg = self._vipConfigT[curVip]
    local extraTime = cfg.onHookOutLineTime
    local min = math.floor(extraTime/60)
    return min
end

function ModelVip:CanUpgrade()
    local curVip = gModelPlayer:GetVipLevel()
    local nextVip = curVip+1
    if self._vipConfigT[nextVip] then
        return true
    end
    return false
end


function ModelVip:ParseConfig()
    self._vipConfigT = {}
    self._vipSortConfigT = {}
    --local minProtectLv = 10000000
    local maxVipLv = 0
    local maxTreaBuy = 0
    for k,v in pairs(GameTable.PremiumLevelRef) do
        local vipLv = v.level
        self._vipConfigT[vipLv]= v
        table.insert(self._vipSortConfigT,v)
        --if v.actionArenaProtect==1 then
        --    minProtectLv = math.min(minProtectLv,v.level)
        --end
        maxVipLv = math.max(maxVipLv,vipLv)
    end
    table.sort(self._vipSortConfigT,function(v1,v2)
        return v1.sort < v2.sort
    end)
    --self._minProtectLv = minProtectLv

    self._maxTreaBuy = maxTreaBuy
    self._maxVipLv = maxVipLv


    local vipPowerDesTypeMap = {}
    for k,v in pairs(GameTable.PremiumPowerDesRef) do
        local type = v.type
        local vipPowerDesLvMap = vipPowerDesTypeMap[type]
        if not vipPowerDesLvMap then
            vipPowerDesLvMap = {}
            vipPowerDesTypeMap[type] = vipPowerDesLvMap
        end
        vipPowerDesLvMap[v.level] = v
    end
    self._vipPowerDesTypeMap = vipPowerDesTypeMap
end

function ModelVip:GetRefByVipLv(vipLv)
    return self._vipConfigT[vipLv]
end

function ModelVip:GetVipHeroBagNumBuy(vipLv)
    local numBuy,vip
    local curVip = vipLv or gModelPlayer:GetVipLevel()
    for i,v in ipairs(self._vipSortConfigT) do
        if numBuy then break end
        local lv,heroBagNumBuy = v.level,v.heroBagNumBuy
        if lv > curVip then
            local curVipData = self._vipConfigT[curVip]
            numBuy = heroBagNumBuy - curVipData.heroBagNumBuy
            vip = lv
        end
    end
    return numBuy,vip
end


function ModelVip:GetMaxTreaBuy()
    return self._maxTreaBuy
end

function ModelVip:GetMaxVipLv()
    return self._maxVipLv
end

function ModelVip:GetAddOnHookLv() --获取下一个增加掉落加成的vip等级
    local vipLv = gModelPlayer:GetVipLevel()
    local vipConfig = self._vipConfigT[vipLv]
    if not vipConfig then
        return vipLv,0
    end
    local onHook=  vipConfig.onHook
    for k = vipLv,self._maxVipLv do
        local temp = self._vipConfigT[k]
        if temp then
            local nextOnHook =  temp.onHook
            if nextOnHook>onHook then
                return k,nextOnHook
            end
        end
    end

    return vipLv,onHook
end
function ModelVip:GetVipShowRef()
    local list = {}
    for i, v in pairs(GameTable.PremiumShowRef) do
        if gModelFunctionOpen:CheckOpenCondition(v.isShow) then
            table.insert(list,v)
        end
    end
    return list
end


function ModelVip:GetVipPowerDesType(type)
    return self._vipPowerDesTypeMap[type]
end

---@return V_VipPowerDesRef
function ModelVip:GetVipPowerRefByTypeAndLv(type,vip)
    local typeRef = self:GetVipPowerDesType(type)
    if not typeRef then return end

    return typeRef[vip]
end

function ModelVip:GetVipPowerDesByTypeAndLv(type,vip)
    local ref = self:GetVipPowerRefByTypeAndLv(type,vip)
    return ref and ccLngText(ref.des) or ""
end


